
import React, { useState, useEffect } from "react";


import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  CheckBoxSlide_Cmpt, TextAreaHRM_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId,   compareJSON, fetchEncryptStream, _monthNames, qryKClient, qryStore, 
loadUrlByMT } from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import {  generateI485 } from "../services/print_service";
import { getMainApplicantInfo } from "../services/customer_fetch_service";








